package com.pos;
import javax.swing.*;import java.awt.*;import java.sql.*;
public class UserFeedbackPanel extends JPanel {private final UserSession s;private final QueryTableModel m=new QueryTableModel();private final JTable t=new JTable(m);private final JTextField order=new JTextField(7),rating=new JTextField(4),comments=new JTextField(30); public UserFeedbackPanel(UserSession s){super(new BorderLayout(8,8));this.s=s;add(UIUtils.title("Service Feedback"),BorderLayout.NORTH);add(new JScrollPane(t),BorderLayout.CENTER);JPanel p=new JPanel();p.add(new JLabel("Completed Order ID"));p.add(order);p.add(new JLabel("Rating 1-5"));p.add(rating);p.add(new JLabel("Comments"));p.add(comments);JButton add=new JButton("Submit Feedback"),refresh=new JButton("Refresh");p.add(add);p.add(refresh);add(p,BorderLayout.SOUTH);add.addActionListener(e->submit());refresh.addActionListener(e->load());load();}
 private void load(){try{m.load("SELECT f.feedback_id,o.order_no,f.rating,f.comments,f.status,f.created_at FROM feedback f JOIN sales_orders o ON o.order_id=f.order_id JOIN customer_profiles cp ON cp.customer_id=f.customer_id WHERE cp.user_id=? ORDER BY f.feedback_id DESC",s.userId);}catch(Exception e){UIUtils.error(this,e);}}
 private void submit(){try(Connection c=DB.getConnection()){int cid=POSService.customerId(s.userId);PreparedStatement v=c.prepareStatement("SELECT order_id FROM sales_orders WHERE order_id=? AND customer_id=? AND order_status='COMPLETED'");v.setInt(1,Integer.parseInt(order.getText()));v.setInt(2,cid);if(!v.executeQuery().next())throw new SQLException("Feedback is allowed only for your completed transaction.");PreparedStatement p=c.prepareStatement("INSERT INTO feedback(customer_id,order_id,rating,comments,status) VALUES(?,?,?,?,'VISIBLE')");p.setInt(1,cid);p.setInt(2,Integer.parseInt(order.getText()));p.setInt(3,Integer.parseInt(rating.getText()));p.setString(4,comments.getText());p.executeUpdate();load();}catch(Exception e){UIUtils.error(this,e);}}
}
